changeSet.sql:
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name = 'attachment' AND column_name = 'status'
    ) THEN
        -- Add column as nullable first so existing rows are not rejected
        ALTER TABLE attachment ADD COLUMN status VARCHAR(20);

        -- Back-fill all existing rows with the default lifecycle state
        UPDATE attachment SET status = 'UPLOADED' WHERE status IS NULL;

        -- Now enforce NOT NULL
        ALTER TABLE attachment ALTER COLUMN status SET NOT NULL;

        -- Set the column default for future inserts
        ALTER TABLE attachment ALTER COLUMN status SET DEFAULT 'UPLOADED';
    END IF;
END $$;
